import 'package:flutter/material.dart';import 'package:pharmacy_wms/Models/app_localizations.dart';import 'package:pharmacy_wms/Models/materialModel.dart';import 'package:pharmacy_wms/main.dart';class ExpiryEditDialog extends StatefulWidget {  final MaterialModel product;  const ExpiryEditDialog({super.key, required this.product});  @override  State<ExpiryEditDialog> createState() => _ExpiryEditDialogState();}class _ExpiryEditDialogState extends State<ExpiryEditDialog> {  DateTime? _expiryDate;  bool _submitted = false;  @override  void initState() {    super.initState();    _expiryDate = widget.product.expiryDateValue;  }  Future<void> _pickDate() async {    final picked = await showDatePicker(      context: context,      initialDate: _expiryDate ?? DateTime.now(),      firstDate: DateTime(2020),      lastDate: DateTime(2100),    );    if (picked != null) setState(() => _expiryDate = picked);  }  void _submit() {    setState(() => _submitted = true);    if (_expiryDate == null) return;    Navigator.pop(context, _expiryDate!.toUtc().toIso8601String());  }  @override  Widget build(BuildContext context) {    final tr = context.tr;    final isDark = Theme.of(context).brightness == Brightness.dark;    return Dialog(      insetPadding: const EdgeInsets.all(24),      backgroundColor: isDark ? const Color(0xFF1B2430) : Colors.white,      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(18)),      child: Container(        width: 460,        padding: const EdgeInsets.all(24),        child: Column(          mainAxisSize: MainAxisSize.min,          crossAxisAlignment: CrossAxisAlignment.start,          children: [            Row(              children: [                Expanded(                  child: Text(                    tr.requestExpiryEdit,                    style: TextStyle(                      fontSize: 22,                      fontWeight: FontWeight.bold,                      color: isDark ? Colors.white : Colors.black,                    ),                  ),                ),                IconButton(                  onPressed: () => Navigator.pop(context),                  icon: const Icon(Icons.close),                ),              ],            ),            const SizedBox(height: 18),            _infoRow(tr.product, widget.product.name, isDark),            _infoRow(tr.sku, widget.product.sku, isDark),            const SizedBox(height: 18),            Text(              tr.newExpiryDate,              style: TextStyle(                fontSize: 13,                fontWeight: FontWeight.w600,                color: isDark ? Colors.white : Colors.black,              ),            ),            const SizedBox(height: 8),            InkWell(              onTap: _pickDate,              borderRadius: BorderRadius.circular(12),              child: InputDecorator(                decoration: InputDecoration(                  prefixIcon: const Icon(Icons.calendar_today_outlined),                  filled: true,                  fillColor:                      isDark ? const Color(0xFF2A3441) : Colors.grey[100],                  border: OutlineInputBorder(                    borderRadius: BorderRadius.circular(12),                    borderSide: BorderSide.none,                  ),                  errorText: _submitted && _expiryDate == null                      ? tr.pleaseSelectDate                      : null,                ),                child: Text(                  _expiryDate == null                      ? tr.selectDate                      : _formatDate(_expiryDate!),                ),              ),            ),            const SizedBox(height: 24),            Row(              mainAxisAlignment: MainAxisAlignment.end,              children: [                TextButton(                  onPressed: () => Navigator.pop(context),                  child: Text(tr.cancel),                ),                const SizedBox(width: 12),                ElevatedButton.icon(                  onPressed: _submit,                  icon: const Icon(Icons.send_outlined),                  label: Text(tr.requestEdit),                  style: ElevatedButton.styleFrom(                    backgroundColor: const Color(0xFF1CA0A5),                    foregroundColor: Colors.white,                  ),                ),              ],            ),          ],        ),      ),    );  }  Widget _infoRow(String label, String value, bool isDark) {    return Padding(      padding: const EdgeInsets.only(bottom: 8),      child: Row(        children: [          SizedBox(            width: 80,            child: Text(              '$label:',              style: TextStyle(                  color: isDark ? Colors.white60 : Colors.black54),            ),          ),          Expanded(            child: Text(              value,              style: TextStyle(                fontWeight: FontWeight.w600,                color: isDark ? Colors.white : Colors.black,              ),            ),          ),        ],      ),    );  }  String _formatDate(DateTime date) {    final month = date.month.toString().padLeft(2, '0');    final day = date.day.toString().padLeft(2, '0');    return '${date.year}-$month-$day';  }}